// Integration test for GET /api/wind-alert — verifies the endpoint returns a
// well-formed gust-alert payload for real coordinates (Mediterranean off Barcelona).
async function testWindAlertEndpoint() {
  const res = await fetch('http://localhost:3001/api/wind-alert?lat=41.35&lon=2.17');
  assertEquals(res.status, 200, 'Wind alert should return 200');

  const data = await res.json();

  // Position/timezone echoed back
  assert(typeof data.latitude === 'number', 'Should include latitude');
  assert(typeof data.longitude === 'number', 'Should include longitude');
  assert(typeof data.timezone === 'string', 'Should include timezone');

  // Core alert fields
  assertEquals(typeof data.alert, 'boolean', 'alert should be a boolean');
  assertEquals(typeof data.gusts, 'number', 'gusts should be a number');
  assertEquals(data.threshold, 25, 'threshold should default to 25 kn when not overridden');
  assert(typeof data.message === 'string' && data.message.length > 0, 'message should be a non-empty string');

  // The alert flag must be consistent with the strict gusts > threshold rule
  assertEquals(data.alert, data.gusts > data.threshold, 'alert should equal gusts > threshold');
}
